      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: [EXECUTE_HOOK],
      calls: ['tool:register'],
      subscribes: [],
    },
    async init({ bus }) {
      bus.registerService<unknown, { output: string }>(
        EXECUTE_HOOK,
