 *
 * Idempotency note: this is called ONCE per session. Re-calling on a
 * non-empty `/permanent` would fail (`git clone` refuses a non-empty
 * target). Bootstrap-fatal ŌĆö the runner can't proceed without a clean
 * workspace.
 */
export async function materializeWorkspace(
  input: MaterializeInput,
): Promise<{ baselineCommit: string }> {
  const { root, bundleBase64 } = input;

  if (bundleBase64 === '') {
    // Defensive: the wire contract says materialize ALWAYS ships a
    // non-empty bundle. An empty bundle here means the host bundler is
    // broken or the wire was tampered with ŌĆö fail loud rather than
    // silently producing an unworkable workspace.
    throw new Error(
      'materializeWorkspace: empty bundleBase64 (host should always ship a baseline bundle)',
    );
  }

  // Two-step: write the bundle bytes to a temp file OUTSIDE the target
  // dir (clone refuses to clone into a non-empty directory), then clone
  // from the bundle file.
  //
  // We pin the bundle to `os.tmpdir()` rather than `${root}.baseline.bundle`
  // because the parent of `root` is often a read-only volume root (e.g.
  // the k8s sandbox mounts /permanent as the workspace dir under
  // `readOnlyRootFilesystem: true`, so writing `/permanent.baseline.bundle`
  // at filesystem `/` fails with EROFS). /tmp is always writable in
  // both subprocess and k8s sandboxes.
  await fs.mkdir(root, { recursive: true });
  const bundlePath = path.join(os.tmpdir(), `ax-baseline-${Date.now()}-${Math.random().toString(36).slice(2, 10)}.bundle`);
  await fs.writeFile(bundlePath, Buffer.from(bundleBase64, 'base64'));
  try {
    await expectOk(
      await runGit(['clone', '--branch', 'main', bundlePath, root]),
      'git clone',
    );
    // Pin refs/heads/baseline to current HEAD (= main = bundle's tip)
    // so the next `git bundle baseline..main` is well-defined.
    // refs/heads/baseline doesn't exist after clone (the bundle only
    // ships refs/heads/main); we create it here pinning to the same
    // OID as main.
    //
    // After this, the contract is:
    //   refs/heads/baseline   ŌĆö the last-accepted state (advances per
    //                           turn via advanceBaseline after host
    //                           accepts).
    //   HEAD/refs/heads/main  ŌĆö current working state; advances on each
    //                           turn-end commit.
    //   git bundle baseline..main main ŌĆö the per-turn thin bundle.
    await expectOk(
      await runGit(['-C', root, 'update-ref', 'refs/heads/baseline', 'HEAD']),
      'git update-ref refs/heads/baseline',
    );
    // Resolve the baseline OID for the caller. The runner uses this to
    // initialize parentVersion for its first commit-notify call: when
    // the workspace has prior history, parentVersion=null on the first
    // turn would cause commit-notify to export the deterministic empty
    // baseline (tipŌēĀHEAD), and the bundler scratch repo would reject
    // the runner's thin bundle with "Repository lacks these prerequisite
    // commits". The fix is to thread the materialize-time tip OID
    // through to the first commit-notify so the host can resolve the
    // matching baseline bundle.
    const head = await runGit(['-C', root, 'rev-parse', 'refs/heads/baseline']);

