export const ARTIFACT_PUBLISH_TOOL_NAME = 'artifact_publish' as const;

/**
 * Phase 2 (`artifact_publish`). The model invokes this tool with a path
 * under /permanent/workspace/** or /permanent/.ax/artifacts/**; the
