      readWorkspace: fakeReader({}),
      supportsDocumentBlocks: true,
    });
    expect(out).toEqual([{ type: 'text', text: 'hello' }]);
  });

  it('maps image attachments to Anthropic image blocks (base64 source)', async () => {
